 33→export function ListItem({
 34→  index,
 35→  icon,
 36→  title,
 37→  subtitle,
 38→  accessories,
 39→  onClick,
 40→}: ListItemProps) {
 41→  const { activeIndex, setActiveIndex } = useListContext();
 42→  const isActive = activeIndex === index;
 43→
 44→  const handleMouseEnter = useCallback(() => {
 45→    setActiveIndex(index);
 46→  }, [
 47→    index,
 48→    setActiveIndex,
 49→  ]);
 50→
 51→  return (
 52→    <div
 53→      id={`list-item-${index}`}
 54→      className={`list-item${isActive ? ' list-item--active' : ''}`}
 55→      data-list-index={index}
 56→      role="option"
 57→      aria-selected={isActive}
 58→      onMouseEnter={handleMouseEnter}
 59→      onClick={onClick}
 60→    >
 61→      <div className="list-item__left">
 62→        {icon && <span className="list-item__icon">{icon}</span>}
 63→        <span className="list-item__title">{title}</span>
 64→        {subtitle && <span className="list-item__subtitle">{subtitle}</span>}
 65→      </div>
 66→      {accessories && accessories.length > 0 && (
 67→        <div className="list-item__accessories">
 68→          {accessories.map((accessory, i) => {
 69→            if (accessory.tag) {
 70→              const hex = accessory.tag.color
 71→                ? ACCESSORY_TAG_COLORS[accessory.tag.color]
 72→                : undefined;
 73→              return (
 74→                <span
 75→                  key={i}
 76→                  className="list-item__accessory-tag"
 77→                  style={
 78→                    hex
 79→                      ? {
 80→                          color: hex,
 81→                          backgroundColor: `${hex}26`,
 82→                        }
 83→                      : undefined
 84→                  }
 85→                >
 86→                  {accessory.tag.text}
 87→                </span>
 88→              );
 89→            }
 90→            return (
 91→              <span key={i} className="list-item__accessory">
 92→                {accessory.icon}
 93→                {accessory.text && (
 94→                  <span className="list-item__accessory-text">
 95→                    {accessory.text}
 96→                  </span>
 97→                )}
 98→              </span>
 99→            );
100→          })}
101→        </div>
102→      )}
103→    </div>
104→  );
105→}
